-----------------------------------------------------------------
function LFightIdleDropCtrl:LFightIdleDropCtrl()
	--所有对象列表{LFightIdleDrop,LFightIdleDrop,...}
	---@type LFightIdleDrop[]
	self._dropList = {}

	--运行标记
	self._isRunning = false
	--缓存

	self._cacheList = {}

	self._dropIdx = 0

	self._dropStayTime = 0
	self._dropDisMin = 0
	self._dropDisMax = 0

	--引用外部创建的pool， 不需要自己进行销毁
	self._simplePool = nil

	self._dropFlyNum = 0

	self._dropSpineName = "Jinbi"

	self._dropShowMonList = {}
	
	self._isClickPickDrop = false
end

------------------------------------------------------------------
function LFightIdleDropCtrl:InitDropData(dropStayTime,dropDisMin,dropDisMax,dropFlyNum,dropByHand)
	self._dropStayTime = dropStayTime
	self._dropDisMin = dropDisMin
	self._dropDisMax = dropDisMax
	self._dropFlyNum = dropFlyNum
	self._dropByHand = dropByHand
end

function LFightIdleDropCtrl:InitDropPool(parentTrans)
	--local simplePool = LSimplePool:New()
	--simplePool:InitPool(parentTrans)

	self._parentTrans = parentTrans

	local simplePool = GF.CreateSimplePool(LPoolTagConst.TAG_BTIDLE_DROP,true)
	if simplePool then
		--先创建对象池
		local spineName = self._dropSpineName
		local spinePath = "Spine/" .. spineName .. "/" .. spineName
		local args = simplePool:MakeArgs(spinePath, spineName, nil, LPoolItemConst.TYPE_SPINE)
		simplePool:InitPoolItem(args)
	end
	self._simplePool = simplePool
end

function LFightIdleDropCtrl:InitAutoDropData(rewardShowList)
	self._autoDropRewardShowList = rewardShowList
	self._isCheckDropAuto = true
	self._isNewMoveType = true
end

