function LFightIdleDropCtrl:MakeDropObject(itemId,order,pos,tarPos,dropScale)
	local idx = self._dropIdx + 1
	self._dropIdx = idx

	local obj = LFightIdleDrop:New()
	obj:Create(idx,self,itemId,order,pos,tarPos,self._parentTrans,dropScale)
	return obj
end

function LFightIdleDropCtrl:GetSimplePool()
	return self._simplePool
end

