---自动掉落
function LFightIdleDropCtrl:CheckAutoDrop(time)
	if not self._autoDropRewardShowList then return end

	local itemDataList = {}
	local recordAutoDropTime = self._recordAutoDropTime
	if not recordAutoDropTime then
		recordAutoDropTime = {}
		self._recordAutoDropTime = recordAutoDropTime
	end

	for k,v in ipairs(self._autoDropRewardShowList) do
		local lastTime = recordAutoDropTime[k]
		if not lastTime then
			lastTime = time
			recordAutoDropTime[k] = lastTime
		else
			local pass = time - lastTime
			if pass > v.time then
				local num = LFightIdleConst.RandIntegerBetween(v.min,v.max)
				if num > 0 then
					table.insert(itemDataList, {iconPath = v.name, itemNum = num})
				end
				recordAutoDropTime[k] = time
			end
		end
	end

	if #itemDataList == 0 then return end

	local order = LFightIdleConst.RandIntegerBetween(-10,10)
	local dropScale = gModelInstance:GetLittleDropScale()

	local pos = self._manager:GetCurrentLeaderPos()

	local dropMin = self._dropDisMin
	local dropMax = self._dropDisMax
	local stayTime = self._dropStayTime

	dropMin = pos.x + 5 - 3.2
	dropMax = pos.x + 5 + 3.2

	local cnt = 0
	for k,v in ipairs(itemDataList) do
		cnt = cnt + v.itemNum
	end
	if cnt <= 0 then return end
	local index = 0
	for k,v in ipairs(itemDataList) do
		for i= 1,v.itemNum do
			index = index + 1

			local dropRange = math.random() * (dropMax - dropMin) + dropMin
			local tarPos = Vector3(dropRange,pos.y,pos.z)

			local dropPos = pos:Clone()
			local mathRand = math.random()
			if mathRand > 0.66 then
				dropPos.y = pos.y + 0.01
			elseif mathRand > 0.33 then
				dropPos.y = pos.y - 0.01
			end

			local obj = self:MakeDropObject(v.iconPath,order,dropPos,tarPos,dropScale)
			self:AddDrop(obj)
			obj:StartLoadIcon()
			obj:StartDrop(stayTime)
		end
	end
end
