---mission 宝物堆
function LFightIdleDropCtrl:DoMissionDrop(pos,minPos,maxPos)
	local order = LFightIdleConst.RandIntegerBetween(-10,10)
	local itemDataList = gModelInstance:GetDropShowMonData()
	local dropScale = gModelInstance:GetLittleDropScale()
	pos = pos:Clone()

	local dropMin = self._dropDisMin
	local dropMax = self._dropDisMax

	dropMin = math.max(pos.x + dropMin, minPos.x)

	local startLeft = pos.x
	local leftDis = startLeft - dropMin

	if leftDis < 0 then
		leftDis = 0
	end

	dropMax = math.min(pos.x + dropMax, maxPos.x)
	local startRight = pos.x
	local rightDis = dropMax - startRight
	if rightDis < 0 then
		rightDis = 0
	end

	local totalDis = leftDis + rightDis
	if totalDis < 0 then
		totalDis = 1
	end

	local cnt = 0
	for k,v in ipairs(itemDataList) do
		cnt = cnt + v.itemNum
	end
	if cnt <= 0 then return end
	local index = 0
	for k,v in ipairs(itemDataList) do
		for i= 1,v.itemNum do
			index = index + 1
			local dropRange = math.random() * totalDis
			if dropRange > leftDis and leftDis > 0 then
				dropRange = startRight + (dropRange - leftDis)
				dropRange = math.min(dropRange, maxPos.x)
			else
				dropRange = startLeft - dropRange
				dropRange = math.max(dropRange, minPos.x)
			end

			local mathRand = math.random()
			local y =  pos.y
			if mathRand > 0.66 then
				y = y + 0.01
			elseif mathRand > 0.33 then
				y = y - 0.01
			end
			local tarPos = Vector3(dropRange,y,pos.z)
			local obj = self:MakeDropObject(v.iconPath,order,tarPos:Clone(),tarPos,dropScale)
			table.insert(self._dropShowMonList, obj)
			obj:StartLoadIcon()
		end
	end

end

