function LFightIdleDropCtrl:DoDropLittle(pos,minPos,maxPos,quality)
	local order = LFightIdleConst.RandIntegerBetween(-10,10)
	local itemDataList = gModelInstance:GetLittleDropShowData(quality)
	local dropScale = gModelInstance:GetLittleDropScale()

	local dropMin = self._dropDisMin
	local dropMax = self._dropDisMax
	local stayTime = self._dropStayTime

	pos = pos:Clone()

	dropMin = pos.x + dropMin
	dropMax = pos.x + dropMax

	if dropMin < minPos.x then
		dropMin = minPos.x
	end

	if dropMax > maxPos.x then
		dropMax = maxPos.x
	end

	local mathRand = math.random()

	if mathRand > 0.66 then
		pos.y = pos.y + 0.01
	elseif mathRand > 0.33 then
		pos.y = pos.y - 0.01
	end

	local cnt = 0
	for k,v in ipairs(itemDataList) do
		cnt = cnt + v.itemNum
	end
	if cnt <= 0 then return end

	local rangeX = 1 / cnt

	local index = 0
	for k,v in ipairs(itemDataList) do
		for i= 1,v.itemNum do
			index = index + 1
			--local offset = (index-cnt/2)*rangeX
			local dropRange = math.random() * (dropMax - dropMin) + dropMin
			local tarPos = Vector3(dropRange,pos.y,pos.z)
			pos = pos:Clone()
			local obj = self:MakeDropObject(v.iconPath,order,pos,tarPos,dropScale)
			self:AddDrop(obj)
			obj:StartLoadIcon()
			obj:StartDrop(stayTime)
		end
	end
end

