---@param dropObj LFightIdleDrop
function LFightIdleDropCtrl:AddDrop(dropObj)
	if(self._isRunning) then
		table.insert(self._cacheList,{true,dropObj})
		return
	end

	table.insert(self._dropList,dropObj)
end

function LFightIdleDropCtrl:RemoveDrop(dropObj)
	if(self._isRunning) then
		table.insert(self._cacheList,{false,dropObj})
		return
	end
	table.removeidata(self._dropList,dropObj)
end

-----------------------------------------------------------------
function LFightIdleDropCtrl:OnRun(time)
	if self._isCheckDropAuto then
		self:CheckAutoDrop(time)
	end

	local dropList = self._dropList

	self._isRunning = true
	local delIndexList = {}

	for k,v in ipairs(dropList) do
		if(not v:OnRun(time)) then
			v:Destroy()
			table.insert(delIndexList,k)
		end
	end
	self._isRunning = false

	for k=#delIndexList,1,-1 do
		table.remove(dropList,delIndexList[k])
	end

	local cacheList = self._cacheList
	self._cacheList = {}
	for k,v in ipairs(cacheList) do
		if v[1] then
			self:AddDrop(v[2])
		else
			self:RemoveDrop(v[2])
		end
	end

	if self._dropFlyNum and self._dropFlyNum > 0 and #dropList >= self._dropFlyNum then
		for k,v in ipairs(dropList) do
			v:StartFlyToWnd()
			v:Destroy()
		end
		return
	end
	local bEnablePick = self._bEnablePick
	local pickMinx,pickMaxx,pickMiny,pickMaxy
	if bEnablePick then
		local pickx = self._pickPos.x
		local picky = self._pickPos.y
		local range = self._dropByHand
		pickMinx,pickMaxx,pickMiny,pickMaxy = pickx - range, pickx + range, picky - range, picky + range
	else
		self._isClickPickDrop = false
	end
	local minx,maxx,miny,maxy = self:GetManager():GetCameraViewBounds()
	local centerX = (minx + maxx) / 2
	
	minx = centerX - 3.2
	maxx = centerX + 3.2

	if self._isNewMoveType then
		local leaderPos = self:GetManager():GetCurrentLeaderPos()
		if leaderPos then
			maxx = leaderPos.x
		end
		for k,v in ipairs(dropList) do
			local pos = v:GetPosition()
			local posx = pos.x
			local posy = pos.y
			if v:IsStay() and posx < maxx then
				v:StartFlyToWnd()
				v:Destroy()
			elseif bEnablePick and v:IsStay() and (posx >= pickMinx and posx <= pickMaxx and posy >= pickMiny and posy <= pickMaxy) then
				v:StartFlyToWnd()
				v:Destroy()
				self._isClickPickDrop = true
			end
		end
	else
		for k,v in ipairs(dropList) do
			local pos = v:GetPosition()
			local posx = pos.x
			local posy = pos.y
			if posx < minx or posx > maxx or posy < miny or posy > maxy then
				v:StartFlyToWnd()
				v:Destroy()
			elseif bEnablePick and v:IsStay() and (posx >= pickMinx and posx <= pickMaxx and posy >= pickMiny and posy <= pickMaxy) then
				v:StartFlyToWnd()
				v:Destroy()
				self._isClickPickDrop = true
			end
		end
	end

	self:DoFlayToWnd()
end

function LFightIdleDropCtrl:AddFlyToWndList(param)
	local flyList = self._flyList or {}
	table.insert(flyList,param)
	self._flyList = flyList
end

function LFightIdleDropCtrl:DoFlayToWnd()
	local flyList = self._flyList
	if not flyList or #flyList == 0 then return end
	self._flyList = {}
	FireEvent(EventNames.BTIDLE_DROP_FLY,flyList)
end
