function LFightIdleDropCtrl:Destroy()

	local dropList = self._dropList
	if(dropList) then
		for k,v in ipairs(dropList) do
			v:Destroy()
		end
		self._dropList = nil
	end

	dropList = self._dropShowMonList
	if(dropList) then
		for k,v in ipairs(dropList) do
			v:Destroy()
		end
		self._dropShowMonList = nil
	end

	--引用外部创建的pool， 不需要自己进行销毁
	--if self._simplePool then
	--	self._simplePool:ClearPool()
	--	self._simplePool:Destroy()
	--	self._simplePool = nil
	--end

	table.removeall(self)
end
